import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { GeoAnalysisResult } from "./types";

const GEO_CLASSES = [
    "Igneous Rock",
    "Sedimentary Rock",
    "Metamorphic Rock",
    "Conglomerate (Rounded Clasts)",
    "Breccia (Angular Clasts)",
    "Sandstone",
    "Limestone",
    "Shale / Mudstone",
    "Quartzite",
    "Marble",
    "Basalt",
    "Granite",
    "Gneiss",
    "Schist",
    "River Boulder",
    "Alluvial / Fluvial Clast",
    "Gemstone / Heavy Mineral",
    "Fossil (Shell)",
    "Fossil (Plant Impression)",
    "Fossil (Coral / Colonial)",
    "Unknown / Needs Lab Analysis"
];

export const analyzeGeologicalSample = async (base64Image: string): Promise<GeoAnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Act as an expert geologist specialized in fluvial systems. Analyze the provided image of a rock, mineral, or fossil sample. 
  Try to classify it into one of the following categories: ${GEO_CLASSES.join(", ")}. 
  Provide a detailed geological interpretation focusing on transport energy, depositional environment, and fluvial context.`;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image.split(',')[1] || base64Image,
          },
        },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          identified: { type: Type.STRING, description: "The specific rock or mineral name from the provided list." },
          confidence: { type: Type.NUMBER, description: "Confidence score between 0 and 100." },
          interpretation: { type: Type.STRING, description: "Detailed geological interpretation." },
          fluvialContext: { type: Type.STRING, description: "Analysis of transport history and environment." },
          geologicalAge: { type: Type.STRING, description: "Estimated geological period if applicable." },
          formationDetails: { type: Type.STRING, description: "Process of how this sample likely formed." }
        },
        required: ["identified", "confidence", "interpretation", "fluvialContext", "formationDetails"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No analysis returned from AI");

  return JSON.parse(text) as GeoAnalysisResult;
};

